public class Solution {
    public static long[] solve(String[] words) {
        int n = words.length;
        long[] answer = new long[n];

        // Preprocess to build a trie for efficient prefix checking
        Trie root = new Trie();
        for (String word : words) {
            root.insert(word);
        }

        // For each index, remove the word and compute the max prefix length
        for (int i = 0; i < n; i++) {
            String removedWord = words[i];
            // Remove the word from the trie
            root.remove(removedWord);

            long maxPrefix = 0;
            for (int j = 0; j < n - 1; j++) {
                String word1 = words[j];
                String word2 = words[j + 1];
                int len = 0;
                while (len < Math.min(word1.length(), word2.length()) && word1.charAt(len) == word2.charAt(len)) {
                    len++;
                }
                maxPrefix = Math.max(maxPrefix, (long) len);
            }

            answer[i] = maxPrefix;

            // Reinsert the word into the trie
            root.insert(removedWord);
        }

        return answer;
    }

    static class Trie {
        private class Node {
            Map<Character, Node> children = new HashMap<>();
            boolean isEndOfWord = false;
        }

        private Node root = new Node();

        public void insert(String word) {
            Node node = root;
            for (char c : word.toCharArray()) {
                if (!node.children.containsKey(c)) {
                    node.children.put(c, new Node());
                }
                node = node.children.get(c);
            }
            node.isEndOfWord = true;
        }

        public void remove(String word) {
            Node node = root;
            for (char c : word.toCharArray()) {
                if (!node.children.containsKey(c)) {
                    return; // Word not found in trie
                }
                node = node.children.get(c);
            }
            node.isEndOfWord = false;
        }
    }
